	function selectMulti() {
		if (this.classList.contains('selected')) {
			this.classList.remove('selected');
		} else {
			this.classList.add('selected');
		}

		// Behavior if 'none' or 'no problems' selected
		const noneOption = quizData[currentQuestion].options.length - 1;
		let selectedElements = document.getElementsByClassName("selected");

		if (this.dataset.answer == noneOption) {
			Array.from(selectedElements).forEach(element => {
				if (element.dataset.answer != noneOption) {
					element.classList.remove('selected');
				}
			});
		} else {
			Array.from(selectedElements).forEach(element => {
				if (element.dataset.answer == noneOption) {
					element.classList.remove('selected');
				}
			});
		}

		if (selectedElements.length > 0) {
			ctaButton.classList.remove('disabled');
		} else {
			ctaButton.classList.add('disabled');
		}
	}

	function bindClickEvents() {
		let ctaButtons = document.getElementsByClassName('quiz-end-cta');
		if (ctaButtons) {
			Array.from(ctaButtons).forEach((button) => {
				button.addEventListener("click", (e) => {
					if (typeof trackQuizEvent === 'function') {
						trackQuizEvent('last_question', e.target.innerText);
