					settings: {
						slidesToShow: 1,
						slidesToScroll: 1
					}
				},
				{
					breakpoint: 1280,
					settings: {
						slidesToShow: 2,
						slidesToScroll: 1
					}
				}
			]
		});

		// Product actions carousel
		$('.product-actions-slick').slick({
			slidesToShow: 4,
			infinite: false,
			slidesToScroll: 1,
			dots: true,
			arrows: true,
			draggable: false,
			responsive: [
				{
					breakpoint: 768,
					settings: {
						slidesToShow: 1,
						slidesToScroll: 1,
						infinite: true,
					}
				},
				{
					breakpoint: 1280,
					settings: {
						slidesToShow: 2,
						slidesToScroll: 1
					}
				}
			]
		});

		// Infographic carousel
		const infographicParams = {
			centerMode: true,
			centerPadding: '0px',
			adaptiveHeight: true,
		};
		initCarousel(infographicParams, '.infographic', true);	

		/**
		 * =============================
		 * INFOGRAPHIC BUTTONS FUNCTIONALITY
		 * =============================
		 */
		// Update active button state when slide changes (in addition to default dot behavior)
		$('.infographic-carousel').on('beforeChange', function(event, slick, currentSlide, nextSlide) {
			// Update active button state
			$('.infographic-button').removeClass('active');
			$('.infographic-button').eq(nextSlide).addClass('active');
		});

		// Infographic button click handlers - navigate to specific slide
		$('.infographic-button').on('click', function() {
			// Create a mapping of data-target to slide index
			var targetKey = $(this).data('target');
			var slideIndex = -1;

			// Find the correct index by iterating through slides
			$('.infographic-content').each(function(index) {
				if ($(this).data('id') === targetKey) {
					slideIndex = index;
					return false; // break the loop
				}
			});

			if (slideIndex >= 0) {
				$('.infographic-carousel').slick('slickGoTo', slideIndex);
			}
		});

		// Set initial active state on first button
		$('.infographic-button').first().addClass('active');
	});
}


/**
 * =============================
 * ACCORDION FUNCTIONALITY
 * =============================
 */

function initAccordion() {
	const acc = document.getElementsByClassName("accordion-slide");

	if (!acc || acc.length === 0) {
		return;
	}

	const toggleAccordion = (e) => {
		let target = e.currentTarget;
		if (!target.classList.contains("active")) {
			Array.from(acc).forEach((slide) => {
				slide.classList.remove("active");
				slide.children[1].style.display = "none";
			});
			target.classList.add("active");
			target.children[1].style.display = "block";
		} else {
			target.classList.remove("active");
			target.children[1].style.display = "none";
		}
	};

	Array.from(acc).forEach((slide) => {
		slide.addEventListener("click", (e) => toggleAccordion(e));
	});
}

/**
 * =============================
 * REVIEWS EXPAND/COLLAPSE
 * =============================
 */

function initReviewsExpand() {
	const buttons = document.querySelectorAll('.quote-attribution');

	buttons.forEach(button => {
		button.addEventListener('click', function() {
			let dots = this.parentNode.querySelector('#dots');
			let moreText = this.parentNode.querySelector('#more');

			if (dots && moreText) {
				if (dots.style.display === "none") {
					dots.style.display = "inline";
					this.innerHTML = "Read more";
					moreText.style.display = "none";
				} else {
					dots.style.display = "none";
					this.innerHTML = "Read less";
					moreText.style.display = "inline";
				}
			}
		});
	});
}

/**
 * =============================
 * INITIALIZATION
 * =============================
 */

// Initialize quiz immediately
initQuiz();

// Initialize when DOM is ready
if (document.readyState === 'loading') {
	document.addEventListener('DOMContentLoaded', () => {
		initMarqueeParallax();
		initCarousels();
		initAccordion();
		initReviewsExpand();
	});
} else {
	initMarqueeParallax();
	initCarousels();
	initAccordion();
	initReviewsExpand();
}

