		// Calculate dynamic width increment based on number of questions
		const totalQuestions = quizData.length;
		const startingWidth = 16;
		const widthPerQuestion = (100 - startingWidth) / totalQuestions;
		const newWidth = startingWidth + (widthPerQuestion * (currentQuestion + 1));

		progress.style.width = newWidth + "%";

		currentQuestion++;

		if (currentQuestion < quizData.length) {
			showQuestion();
		} else {
